```typescript
import { test, expect } from '@playwright/test';

test.describe('Basic HTML Rendering', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('file://' + process.env.TEST_EXPORT_PATH);
  });

  test('renders complete HTML document', async ({ page }) => {
    // Document structure
    await expect(page.locator('html')).toBeAttached();
    await expect(page.locator('head')).toBeAttached();
    await expect(page.locator('body')).toBeAttached();

    // Essential elements present
    await expect(page.locator('header.conversation-header')).toBeVisible();
    await expect(page.locator('main.conversation')).toBeVisible();

    // Console should have no errors
    const errors: string[] = [];
    page.on('console', msg => {
      if (msg.type() === 'error') errors.push(msg.text());
    });
    await page.waitForLoadState('networkidle');
    expect(errors).toHaveLength(0);
  });

  test('displays all messages in order', async ({ page }) => {
    const messages = page.locator('.message');
    await expect(messages).toHaveCount(42); // Expected count from fixture

    // Verify order by checking data-idx attributes
    const indices = await messages.evaluateAll(els =>
      els.map(el => parseInt(el.getAttribute('data-idx') || '0'))
    );
    expect(indices).toEqual([...indices].sort((a, b) => a - b));
  });

  test('syntax highlighting applied to code blocks', async ({ page }) => {
    const codeBlocks = page.locator('pre code[class*="language-"]');

    // Wait for Prism.js to process (or fallback to work)
    await page.waitForTimeout(1000);

    const count = await codeBlocks.count();
    expect(count).toBeGreaterThan(0);

    // Check for syntax tokens (either Prism or fallback styling)
    const hasHighlighting = await page.evaluate(() => {
      const code = document.querySelector('pre code');
      if (!code) return false;
      // Prism adds token spans, or we have fallback background
      return code.querySelectorAll('.token').length > 0 ||
             window.getComputedStyle(code).backgroundColor !== 'rgba(0, 0, 0, 0)';
    });
    expect(hasHighlighting).toBe(true);
  });

  test('timestamps display correctly', async ({ page }) => {
    const timestamps = page.locator('time[datetime]');
    const count = await timestamps.count();
    expect(count).toBeGreaterThan(0);

    // Verify datetime attribute is valid ISO format
    const datetimes = await timestamps.evaluateAll(els =>
      els.map(el => el.getAttribute('datetime'))
    );
    for (const dt of datetimes) {
      expect(new Date(dt!).toISOString()).toBeTruthy();
    }
  });
});
```

